// Example: Efficient task scheduler in JavaScript
class TaskScheduler {
  constructor() {
    this.tasks = [];
  }

  addTask(task) {
    this.tasks.push(task);
    this.tasks.sort((a, b) => a.priority - b.priority);
  }

  executeNext() {
    const nextTask = this.tasks.shift();
    console.log(`Executing: ${nextTask.name}`);
    return nextTask;
  }
}

const scheduler = new TaskScheduler();
scheduler.addTask({ name: 'Fix bug', priority: 2 });
scheduler.addTask({ name: 'Write documentation', priority: 1 });
scheduler.executeNext(); // Output: "Executing: Write documentation"
